using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        _logger = logger;
    }

    public string ModelPath => _modelPath;

    public void TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketController : ControllerBase
{
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < CategoryLabels.Length; i++)
            confidence[CategoryLabels[i]] = prediction.Score[i];

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

